import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { createFileRoute, useNavigate, useSearch } from "@tanstack/react-router";
import { z } from "zod";

import { ClientForm } from "@/components/forms/client-form";
import { Client_FormSchema } from "@/lib/form-schemas/client";
import NavLayout from "@/components/layouts/nav-layout";
import { rpc } from "@/rpc/client";

export const Route = createFileRoute("/(protected)/(app)/clients/new")({
  component: NewClientPage,
  validateSearch: z.object({
    draftId: z.string().optional(),
  }),
});

function NewClientPage() {
  const { draftId } = useSearch({ from: Route.id });
  const navigate = useNavigate();
  const queryClient = useQueryClient();

  const { data: draft } = useQuery({
    ...rpc.draft.getById.queryOptions({
      input: { id: Number(draftId) },
    }),
    enabled: !!draftId,
  });

  const parsed = draft?.data
    ? Client_FormSchema.safeParse(draft.data)
    : undefined;
  const defaultValues = parsed?.success ? parsed.data : undefined;

  const createMutation = useMutation({
    mutationFn: (input: z.infer<typeof Client_FormSchema>) =>
      rpc.client.create.call(input),
    onSuccess: async (data) => {
      if (!data) return;
      queryClient.invalidateQueries({ queryKey: ["client"] });
      if (draftId) {
        await rpc.draft.delete.call({ id: Number(draftId) });
        queryClient.invalidateQueries({ queryKey: ["draft"] });
      }
      navigate({
        params: { clientId: String(data.id) },
        to: "/clients/$clientId",
      });
    },
  });

  const saveDraftMutation = useMutation({
    mutationFn: (input: z.infer<typeof Client_FormSchema>) =>
      rpc.draft.create.call({
        data: input as Record<string, unknown>,
        entityType: "client",
        title: input.name,
      }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["draft"] });
    },
  });

  return (
    <NavLayout
      baseUrl="/clients"
      label="Clients"
      leftItems={<div>Create New</div>}
      rightItems={
        <p className="text-muted-foreground text-sm">
          Add a new client to the system
        </p>
      }
    >
      <div className="mx-auto my-16 max-w-xl">
        <ClientForm
          defaultValues={defaultValues}
          isPending={createMutation.isPending}
          isSaveDraftPending={saveDraftMutation.isPending}
          mode="create"
          onSaveDraft={(values) => saveDraftMutation.mutate(values)}
          onSubmit={(values) => createMutation.mutate(values)}
        />
      </div>
    </NavLayout>
  );
}

